var maximumXor = function(s, t) {
    let ones = 0;
    for (const c of t) if (c === '1') ones++;
    let zeros = t.length - ones;
    const res = [];
    for (const c of s) {
        if (c === '0') {
            if (ones > 0) { res.push('1'); ones--; }
            else { res.push('0'); zeros--; }
        } else {
            if (zeros > 0) { res.push('1'); zeros--; }
            else { res.push('0'); ones--; }
        }
    }
    return res.join('');
};
